def get_all_pairs():
    all_pairs = []
    for category, pairs in PAIRS.items():
        for safe, unsafe in pairs:
            all_pairs.append({
                "category": category,
                "safe": safe,
                "unsafe": unsafe
            })
    return all_pairs

if __name__ == "__main__":
    pairs = get_all_pairs()
    print(f"Total pairs: {len(pairs)}")
    for category in PAIRS:
        count = len(PAIRS[category])
        print(f"  {category}: {count} pairs")